package com.example.bankingapp;

import android.os.Bundle;
import android.widget.TextView;
import androidx.appcompat.app.AppCompatActivity;

public class MainActivity extends AppCompatActivity {
    private double accountBalance = 1000.00;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        updateAccountBalanceDisplay();
    }

    private void updateAccountBalanceDisplay() {
        TextView balanceTextView = findViewById(R.id.balanceTextView);
        balanceTextView.setText("Balance: $" + String.format("%.2f", accountBalance));
    }

    private boolean processTransaction(double amount) {
        if (amount <= 0) {
            // Invalid transaction amount
            return false;
        }
        
        if (amount > accountBalance) {
            // Insufficient funds
            return false;
        }

        accountBalance -= amount;
        updateAccountBalanceDisplay();
        return true;
    }
}

